import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { handleError, handleSuccess } from '../utils';
import { ToastContainer } from 'react-toastify';

function Home() {
    const [loggedInUser, setLoggedInUser] = useState('');
    const [userProfile, setUserProfile] = useState(null);  // State pour le profil de l'utilisateur
    const [products] = useState('');
    const navigate = useNavigate();

    useEffect(() => {
        const userId = localStorage.getItem('loggedInUserId');  // Assurez-vous de stocker l'ID utilisateur dans le localStorage lors de la connexion
        setLoggedInUser(localStorage.getItem('loggedInUser'));

        if (userId) {
            fetchUserProfile(userId);  // Récupérer les informations du profil de l'utilisateur
        }
    }, []);

    const fetchUserProfile = async (userId) => {
        try {
            const response = await axios.get(`http://localhost:5001/users/${userId}`);
            if (response.data.success) {
                setUserProfile(response.data.user);  // Stocker le profil de l'utilisateur dans l'état
            } else {
                handleError('User not found');
            }
        } catch (error) {
            handleError('Failed to fetch user profile');
        }
    };

    const handleLogout = (e) => {
        localStorage.removeItem('token');
        localStorage.removeItem('loggedInUser');
        localStorage.removeItem('loggedInUserId');  // Supprimer l'ID utilisateur aussi
        handleSuccess('User Loggedout');
        setTimeout(() => {
            navigate('/login');
        }, 1000);
    }

    return (
        <div>
            <h1>Welcome {loggedInUser}</h1>
            <button onClick={handleLogout}>Logout</button>

            {/* Affichage du profil de l'utilisateur */}
            {userProfile && (
                <div>
                    <h3>User Profile</h3>
                    <p><strong>Name:</strong> {userProfile.name}</p>
                    <p><strong>Email:</strong> {userProfile.email}</p>
                    <p><strong>Role:</strong> {userProfile.role}</p>
                </div>
            )}

            {/* Affichage des produits */}
            <div>
                {products && products?.map((item, index) => (
                    <ul key={index}>
                        <span>{item.name} : {item.price}</span>
                    </ul>
                ))}
            </div>

            <ToastContainer />
        </div>
    )
}

export default Home;
